        assertThat(cwp.departurePort).isEqualTo(dep)
    }

    @Test
    fun `departurePort returns null when no departure exists`() {
        val poc = port(id = 1, type = PortType.PORT_OF_CALL)
        val cwp = CruiseWithPorts(cruise = cruise(id = 1), ports = listOf(poc))
        assertThat(cwp.departurePort).isNull()
    }

