        val poc2 = port(id = 3, type = PortType.PORT_OF_CALL, portName = "Jamaica")
        val ret = port(id = 4, type = PortType.RETURN)
        val cwp = CruiseWithPorts(cruise = cruise(id = 1), ports = listOf(dep, poc1, poc2, ret))
        assertThat(cwp.portsOfCall).containsExactly(poc1, poc2)
    }

