        assertThat(cwp.portsOfCall).isEmpty()
    }

    @Test
    fun `allPortsChronological sorts by date then sortOrder`() {
        val ret = port(id = 3, type = PortType.RETURN, date = LocalDate.of(2026, 12, 21), sortOrder = Int.MAX_VALUE)
        val dep = port(id = 1, type = PortType.DEPARTURE, date = LocalDate.of(2026, 12, 14), sortOrder = 0)
        val poc = port(id = 2, type = PortType.PORT_OF_CALL, date = LocalDate.of(2026, 12, 16), sortOrder = 1)
        // Add out of order
        val cwp = CruiseWithPorts(cruise = cruise(id = 1), ports = listOf(ret, poc, dep))
        val sorted = cwp.allPortsChronological
        assertThat(sorted).containsExactly(dep, poc, ret).inOrder()
    }

